    int left = 0;
    int right = n - 1;

    while (left < right) {
        int mid = left + (right - left) / 2;

        // If the element is increasing towards the right, the peak is on the right side.
        if (nums[mid] < nums[mid + 1]) {
            left = mid + 1;
        } else {
            // If the element is decreasing or at the peak, the peak is at or to the left of mid.
            right = mid;
        }
    }

    peak_index = left;

    // Step 2: Calculate sums

    // Sum of the increasing part: nums[0] to nums[peak_index]
    long sum_inc = 0;
    for (int i = 0; i <= peak_index; i++) {
        sum_inc += nums[i];
    }

    // Sum of the decreasing part: nums[peak_index] to nums[n-1]
    long sum_dec = 0;
    for (int i = peak_index; i < n; i++) {
        sum_dec += nums[i];
    }

    // Step 3: Compare and return
    if (sum_inc > sum_dec) {
        return 0L; // Increasing sum is greater
    } else if (sum_dec > sum_inc) {
        return 1L; // Decreasing sum is greater
    } else {
        return -1L; // Sums are equal
    }
}
